INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", "ヒヨリ", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 44, 27, 8, "獣人族", "人助け、応援", 100101, 2, 0, "人助けが大好き！　前向き格闘娘", 16, "東山奈央", "A", 155);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", "ユイ", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 47, 5, 4, "ヒューマン", "料理、人間観察", 100201, 2, 0, "戦闘のサポートが得意な、心優しい少女", 17, "種田梨沙", "O", 158);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", "レイ", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 46, 12, 1, "魔族", "読書、乗馬、お茶", 100301, 2, 0, "クールで何事にも真っ直ぐな剣士", 18, "早見沙織", "B", 163);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("リトルリリカル", "ミソギ", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 27, 10, 8, "ヒューマン", "いたずら、探検", 100401, 5, 0, "探検好きのイタズラっ子", 9, "諸星すみれ", "O", 128);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("王宮騎士団（NIGHTMARE）", "マツリ", "？？？", 40, 25, 11, "獣人族", "ヒーローごっこ", 100501, 8, 0, "ヒーローに憧れる騎士見習いの少女", 12, "下田麻美", "O", 146);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", "アカリ", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 42, 22, 11, "魔族", "サックス", 100601, 7, 0, "甘え上手なみんなの人気者", 13, "浅倉杏美", "O", 150);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", "ミヤコ", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 32, 23, 1, "魔族", "プリンを食べること", 100701, 7, 0, "プリン大好きゴースト娘", 14, "雨宮天", "B", 130);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ヴァイスフリューゲル　ランドソル支部", "ユキ", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 40, 10, 10, "エルフ", "鏡で自分を見ること", 100801, 15, 0, "ボクは誰よりも美しい", 14, "大空直美", "AB", 150);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トワイライトキャラバン", "アンナ", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 45, 5, 7, "魔族", "小説執筆", 100901, 13, 0, "前世を信じる中二病患者、「疾風の冥姫」", 17, "髙野麻美", "A", 159);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("自警団（カォン）", "マホ", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 42, 22, 9, "獣人族", "空想、ぬいぐるみ集め", 101001, 10, 0, "マホマホ王国のプリンセス", 16, "内田真礼", "O", 155);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ラビリンス", "リノ", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 44, 25, 8, "ヒューマン", "お裁縫", 101101, 3, 0, "人懐っこくてマシンガントークな妹系少女", 15, "阿澄佳奈", "A", 156);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("フォレスティエ", "ハツネ", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 46, 24, 12, "エルフ", "妹と遊ぶこと、二度寝、昼寝、早寝", 101201, 6, 0, "みんなのために超能力を使う眠り姫", 17, "大橋彩香", "A", 156);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トワイライトキャラバン", "ナナカ", "", 55, 21, 8, "魔族", "読書、魔法", 101301, 13, 0, "オタク全開な魔法少女", 18, "佳村はるか", "O", 166);
