INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("フォレスティエ", "ミサト", "test", 54, 5, 9, "エルフ", "絵本作り", 101501, 6, 0, "母性溢れる優しいみんなの「ミサト先生」", 21, "國府田マリ子", "O", 165);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ルーセント学院", "スズナ", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 48, 10, 4, "魔族", "ファッション", 101601, 14, 0, "天真爛漫で人気者のカリスマモデル", 17, "上坂すみれ", "O", 167);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("自警団（カォン）", "カオリ", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 53, 7, 7, "獣人族", "踊り、空手", 101701, 10, 0, "いつでも「なんくるないさ～」な天然娘", 17, "高森奈津美", "A", 158);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ルーセント学院", "イオ", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 52, 14, 8, "魔族", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 101801, 14, 0, "多くの男性を魅了する無垢な女教師", 23, "伊藤静", "B", 162);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("リトルリリカル", "ミミ", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 21, 3, 4, "獣人族", "かわいいもの集め", 102001, 5, 0, "お歌もにんじんも、ウサギさんも大好き♪", 10, "日高里菜", "O", 117);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", "クルミ", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 40, 9, 6, "ヒューマン", "観劇、おままごと", 102101, 9, 0, "泣き虫で臆病な守ってあげたい女の子", 12, "植田佳奈", "B", 150);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", "ヨリ", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 40, 22, 11, "魔族", "ゲーム全般", 102201, 7, 0, "人見知りであまのじゃくな女の子", 13, "原紗友里", "O", 150);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", "アヤネ", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 38, 10, 5, "ヒューマン", "屋内でできる遊び", 102301, 9, 0, "ぷうきちといつも一緒！", 14, "芹澤優", "B", 148);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", "スズメ", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 43, 12, 12, "ヒューマン", "ご奉仕", 102501, 9, 0, "お嬢さまのためにがんばるドジっ娘メイド", 15, "悠木碧", "O", 154);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("牧場（エリザベスパーク）", "リン", "test", 42, 1, 1, "獣人族", "あんパン", 102601, 11, 0, "遊びと睡眠が何より大事なぐうたら娘", 17, "小岩井ことり", "B", 144);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トワイライトキャラバン", "エリコ", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 43, 30, 7, "魔族", "実験、裁縫、料理", 102701, 13, 0, "運命の相手に一途すぎる乙女", 16, "橋本ちなみ", "B", 154);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", "サレン", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 43, 4, 10, "エルフ", "経営、お茶会", 102801, 9, 0, "救護院を経営する優しい庶民派お嬢様", 17, "堀江由衣", "A", 156);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("カルミナ", "ノゾミ", "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 40, 24, 1, "ヒューマン", "舞台鑑賞、ダンス", 102901, 4, 0, "歌って踊れる大人気アイドル", 17, "日笠陽子", "B", 157);
