INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", "シノブ", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 42, 22, 12, "魔族", "占い", 103101, 7, 0, "占いが得意な霊能少女", 18, "大坪由佳", "AB", 157);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", "アキノ", "この私とともにいる限り、\nお金に不自由はさせませんわ！", 45, 12, 3, "ヒューマン", "慈善事業", 103201, 12, 0, "一人前の商人を目指すパワフルお嬢様", 18, "松嵜麗", "AB", 157);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("牧場（エリザベスパーク）", "マヒル", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 35, 3, 3, "ヒューマン", "漫才", 103301, 11, 0, "みんなを笑顔にするお笑い牧場主", 20, "新田恵海", "B", 142);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", "ユカリ", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 55, 16, 3, "エルフ", "ウインドーショッピング", 103401, 12, 0, "純情でほっとけない大人の女性", 22, "今井麻美", "A", 164);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("リトルリリカル", "キョウカ", "test", 21, 2, 2, "エルフ", "お勉強", 103601, 5, 0, "礼儀正しくしっかり者のちびっ子優等生", 8, "小倉唯", "A", 118);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("王宮騎士団（NIGHTMARE）", "トモ", "test", 43, 11, 8, "ヒューマン", "剣術、年長者をからかう", 103701, 8, 0, "義理堅くてからかい好きな剣術少女", 13, "茅原実里", "A", 149);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("牧場（エリザベスパーク）", "シオリ", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 40, 3, 11, "獣人族", "読書、お散歩", 103801, 11, 0, "読書が趣味の病弱少女", 14, "小清水亜美", "A", 153);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("フォレスティエ", "アオイ", "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 44, 6, 6, "エルフ", "友達作りのイメトレ", 104001, 6, 0, "「友達」に憧れる、エルフの森の女の子", 13, "花澤香菜", "AB", 158);
