INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("自警団（カォン）", "マコト", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 54, 9, 8, "獣人族", "お菓子作り", 104301, 10, 0, "男勝りで情に厚いワイルド娘", 17, "小松未可子", "O", 168);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", "イリヤ", "test", 50, 5, 5, "魔族", "世界征服", 104401, 7, 0, "かつては夜を支配した最強の吸血鬼", "??", "丹下桜", "A", 172);
