INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", "タマキ", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 48, 1, 3, "獣人族", "猫とたわむれること", 104601, 12, 0, "弱きを助け強きをくじく猫娘", 19, "沼倉愛美", "AB", 158);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("王宮騎士団（NIGHTMARE）", "ジュン", "？？？", 50, 25, 10, "ヒューマン", "格闘技、湯浴み", 104701, 8, 0, "素顔を見せない冷静沈着な女性騎士", 25, "川澄綾子", "A", 171);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", "ミフユ", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 49, 11, 11, "ヒューマン", "傭兵などのアルバイト", 104801, 12, 0, "仕事も私事も効率優先な傭兵少女", 20, "田所あずさ", "O", 163);
