INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("メルクリウス財団", "ミフユ（サマー）", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 49, 11, 11, "ヒューマン", "傭兵などのアルバイト", 108001, 12, 0, "仕事も私事も効率優先な傭兵少女", 20, "田所あずさ", "O", 163);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", "シノブ（ハロウィン）", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 42, 22, 12, "魔族", "占い", 108101, 7, 0, "占いが得意な霊能少女", 18, "大坪由佳", "AB", 157);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("悪魔偽王国軍（ディアボロス）", "ミヤコ（ハロウィン）", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 32, 23, 1, "魔族", "プリンを食べること", 108201, 7, 0, "プリン大好きゴースト娘", 14, "雨宮天", "B", 130);
