INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("カルミナ", "チカ（クリスマス）", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 46, 3, 6, "ヒューマン", "各種楽器", 108401, 4, 0, "人々を守るために歌う、唱喚士の少女", 17, "福原綾香", "O", 163);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", "クルミ（クリスマス）", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 40, 9, 6, "ヒューマン", "観劇、おままごと", 108501, 9, 0, "泣き虫で臆病な守ってあげたい女の子", 12, "植田佳奈", "B", 150);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("サレンディア救護院", "アヤネ（クリスマス）", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 38, 10, 5, "ヒューマン", "屋内でできる遊び", 108601, 9, 0, "ぷうきちといつも一緒！", 14, "芹澤優", "B", 148);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", "ヒヨリ（ニューイヤー）", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 44, 27, 8, "獣人族", "人助け、応援", 108701, 2, 0, "人助けが大好き！　前向き格闘娘", 16, "東山奈央", "A", 155);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", "ユイ（ニューイヤー）", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 47, 5, 4, "ヒューマン", "料理、人間観察", 108801, 2, 0, "戦闘のサポートが得意な、心優しい少女", 17, "種田梨沙", "O", 158);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トゥインクルウィッシュ", "レイ（ニューイヤー）", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 46, 12, 1, "魔族", "読書、乗馬、お茶", 108901, 2, 0, "クールで何事にも真っ直ぐな剣士", 18, "早見沙織", "B", 163);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("トワイライトキャラバン", "エリコ（バレンタイン）", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 43, 30, 7, "魔族", "実験、裁縫、料理", 109001, 13, 0, "運命の相手に一途すぎる乙女", 16, "橋本ちなみ", "B", 154);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("ラビリンス", "シズル（バレンタイン）", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 54, 24, 10, "ヒューマン", "家事全般", 109101, 3, 0, "お姉ちゃんがお世話してあげるからねっ！", 18, "生天目仁美", "O", 168);
