INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES ("？？？", "グレア", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 67, 3, 11, "半人半竜", "ピアノ", 109401, "", 0, "人を超越した力を有す心優しい竜姫", 17, "福原綾香", "B", 167);
